using System.Globalization;using System.Xml.Linq;using Aspose.Cells_FOSS.Testing;using DocumentFormat.OpenXml.Packaging;using DocumentFormat.OpenXml.Spreadsheet;namespace Aspose.Cells_FOSS.WorksheetSettingsOpenXmlTests;internal static class Program{    private static readonly XNamespace MainNs = "http://schemas.openxmlformats.org/spreadsheetml/2006/main";    private static readonly XNamespace RelationshipNs = "http://schemas.openxmlformats.org/officeDocument/2006/relationships";    private static int Main()    {        return TestRunner.Run(            "WorksheetSettings.OpenXmlTests",            new TestCase("worksheet_visibility_matches_openxml_sdk", WorksheetVisibilityMatchesOpenXmlSdk),            new TestCase("worksheet_settings_and_values_match_openxml_sdk", WorksheetSettingsAndValuesMatchOpenXmlSdk),            new TestCase("worksheet_view_and_tab_color_match_openxml_sdk", WorksheetViewAndTabColorMatchOpenXmlSdk),            new TestCase("worksheet_protection_match_openxml_sdk", WorksheetProtectionMatchOpenXmlSdk),            new TestCase("autofilter_matches_openxml_sdk", AutoFilterMatchesOpenXmlSdk),            new TestCase("adjacent_columns_are_combined_and_read_consistently", AdjacentColumnsAreCombinedAndReadConsistently),            new TestCase("merge_only_dimension_matches_openxml_sdk", MergeOnlyDimensionMatchesOpenXmlSdk),            new TestCase("openxml_created_visibility_loads_in_library", OpenXmlCreatedVisibilityLoadsInLibrary),            new TestCase("openxml_created_settings_and_values_load_in_library", OpenXmlCreatedSettingsAndValuesLoadInLibrary),            new TestCase("openxml_created_sheet_view_loads_in_library", OpenXmlCreatedSheetViewLoadsInLibrary),            new TestCase("openxml_created_sheet_protection_loads_in_library", OpenXmlCreatedSheetProtectionLoadsInLibrary),            new TestCase("openxml_created_autofilter_loads_in_library", OpenXmlCreatedAutoFilterLoadsInLibrary),            new TestCase("openxml_created_columns_load_in_library", OpenXmlCreatedColumnsLoadInLibrary),            new TestCase("openxml_created_merge_only_dimension_loads_in_library", OpenXmlCreatedMergeOnlyDimensionLoadsInLibrary));    }    private static void WorksheetVisibilityMatchesOpenXmlSdk()    {        using var temp = new TemporaryDirectory("worksheet-openxml-visibility");        var path = temp.GetPath("visibility.xlsx");        var workbook = new Workbook();        workbook.Worksheets[0].Name = "Visible";        var hiddenIndex = workbook.Worksheets.Add("Hidden");        var veryHiddenIndex = workbook.Worksheets.Add("VeryHidden");        workbook.Worksheets[hiddenIndex].VisibilityType = VisibilityType.Hidden;        workbook.Worksheets[veryHiddenIndex].VisibilityType = VisibilityType.VeryHidden;        workbook.Save(path);        var loaded = new Workbook(path);        AssertEx.Equal(VisibilityType.Visible, loaded.Worksheets["Visible"].VisibilityType);        AssertEx.Equal(VisibilityType.Hidden, loaded.Worksheets["Hidden"].VisibilityType);        AssertEx.Equal(VisibilityType.VeryHidden, loaded.Worksheets["VeryHidden"].VisibilityType);        var snapshots = ReadWorkbookSnapshot(path);        AssertEx.Equal(3, snapshots.Count);        AssertEx.Equal("Visible", snapshots[0].Name);        AssertEx.Equal("Visible", snapshots[0].Visibility);        AssertEx.Equal("Hidden", snapshots[1].Name);        AssertEx.Equal("Hidden", snapshots[1].Visibility);        AssertEx.Equal("VeryHidden", snapshots[2].Name);        AssertEx.Equal("VeryHidden", snapshots[2].Visibility);    }    private static void WorksheetSettingsAndValuesMatchOpenXmlSdk()    {        using var temp = new TemporaryDirectory("worksheet-openxml-settings");        var path = temp.GetPath("worksheet-settings.xlsx");        var workbook = WorksheetScenarioFactory.CreateWorksheetSettingsWorkbook();        workbook.Save(path);        var loaded = new Workbook(path);        WorksheetScenarioFactory.AssertWorksheetSettings(loaded);        var snapshots = ReadWorkbookSnapshot(path);        AssertEx.Equal(2, snapshots.Count);        var snapshot = snapshots.Single(delegate(WorksheetSnapshot item) { return item.Name == "Layout"; });        AssertEx.Equal("Layout", snapshot.Name);        AssertEx.Equal("Hidden", snapshot.Visibility);        AssertEx.Equal("A1:C4", snapshot.Dimension);        AssertEx.Equal("Merged", snapshot.Cells["A1"]);        AssertEx.Equal("99", snapshot.Cells["C4"]);        AssertRow(snapshot, 1, 22.5d, false);        AssertRow(snapshot, 3, null, true);        AssertColumn(snapshot, 0, 0, 18.25d, false);        AssertColumn(snapshot, 2, 2, null, true);        AssertEx.Equal(1, snapshot.MergeReferences.Count);        AssertEx.Equal("A1:B2", snapshot.MergeReferences[0]);        var layoutSheet = loaded.Worksheets["Layout"];        AssertEx.NotNull(layoutSheet);        AssertEx.Equal(layoutSheet!.Cells["A1"].StringValue, snapshot.Cells["A1"]);        AssertEx.Equal(layoutSheet.Cells["C4"].StringValue, snapshot.Cells["C4"]);        AssertEx.Equal(layoutSheet.Cells.Rows[1].Height ?? 0d, snapshot.Rows[1].Height ?? 0d);        AssertEx.Equal(layoutSheet.Cells.Rows[3].IsHidden, snapshot.Rows[3].Hidden);        AssertEx.Equal(layoutSheet.Cells.Columns[0].Width ?? 0d, snapshot.Columns[0].Width ?? 0d);        AssertEx.Equal(layoutSheet.Cells.Columns[2].IsHidden, snapshot.Columns[1].Hidden);    }    private static void WorksheetViewAndTabColorMatchOpenXmlSdk()    {        using var temp = new TemporaryDirectory("worksheet-openxml-view");        var path = temp.GetPath("worksheet-view.xlsx");        var workbook = WorksheetScenarioFactory.CreateWorksheetSettingsWorkbook();        workbook.Save(path);        var loaded = new Workbook(path);        WorksheetScenarioFactory.AssertWorksheetSettings(loaded);        var snapshots = ReadWorkbookSnapshot(path);        AssertEx.Equal(2, snapshots.Count);        var snapshot = snapshots.Single(delegate(WorksheetSnapshot item) { return item.Name == "Layout"; });        AssertEx.Equal("FF224466", snapshot.TabColor);        AssertEx.False(snapshot.ShowGridLines);        AssertEx.False(snapshot.ShowRowColumnHeaders);        AssertEx.False(snapshot.ShowZeros);        AssertEx.True(snapshot.RightToLeft);        AssertEx.Equal(85, snapshot.Zoom);    }    private static void WorksheetProtectionMatchOpenXmlSdk()    {        using var temp = new TemporaryDirectory("worksheet-openxml-protection");        var path = temp.GetPath("worksheet-protection.xlsx");        var workbook = WorksheetScenarioFactory.CreateWorksheetSettingsWorkbook();        workbook.Save(path);        var loaded = new Workbook(path);        WorksheetScenarioFactory.AssertWorksheetSettings(loaded);        var snapshots = ReadWorkbookSnapshot(path);        AssertEx.Equal(2, snapshots.Count);        var snapshot = snapshots.Single(delegate(WorksheetSnapshot item) { return item.Name == "Layout"; });        AssertEx.True(snapshot.IsProtected);        AssertEx.True(snapshot.ProtectObjects);        AssertEx.True(snapshot.ProtectScenarios);        AssertEx.True(snapshot.ProtectFormatCells);        AssertEx.True(snapshot.ProtectInsertRows);        AssertEx.True(snapshot.ProtectAutoFilter);        AssertEx.True(snapshot.ProtectSelectLockedCells);        AssertEx.True(snapshot.ProtectSelectUnlockedCells);    }    private static void AutoFilterMatchesOpenXmlSdk()
    {
        using var temp = new TemporaryDirectory("worksheet-openxml-autofilter");
        var path = temp.GetPath("autofilter.xlsx");

        var workbook = AutoFilterScenarioFactory.CreateAutoFilterWorkbook();
        workbook.Save(path);

        var loaded = new Workbook(path);
        AutoFilterScenarioFactory.AssertAutoFilter(loaded);

        using var document = SpreadsheetDocument.Open(path, false);
        var workbookPart = document.WorkbookPart ?? throw new InvalidOperationException("WorkbookPart is missing.");
        var worksheetPart = workbookPart.WorksheetParts.First();
        var worksheetXml = XDocument.Load(worksheetPart.GetStream());
        var autoFilter = worksheetXml.Root?.Element(MainNs + "autoFilter");
        AssertEx.NotNull(autoFilter);
        AssertEx.Equal("A1:E6", ((string?)autoFilter!.Attribute("ref") ?? string.Empty).ToUpperInvariant());

        var filterColumns = autoFilter.Elements(MainNs + "filterColumn").ToList();
        AssertEx.Equal(5, filterColumns.Count);
        AssertEx.Equal("1", (string?)filterColumns[0].Attribute("hiddenButton") ?? string.Empty);
        AssertEx.Equal("Open", (string?)filterColumns[0].Element(MainNs + "filters")?.Elements(MainNs + "filter").First().Attribute("val") ?? string.Empty);
        AssertEx.Equal("greaterThanOrEqual", (string?)filterColumns[1].Element(MainNs + "customFilters")?.Elements(MainNs + "customFilter").First().Attribute("operator") ?? string.Empty);
        AssertEx.Equal("3", (string?)filterColumns[2].Element(MainNs + "colorFilter")?.Attribute("dxfId") ?? string.Empty);
        AssertEx.Equal("thisMonth", (string?)filterColumns[3].Element(MainNs + "dynamicFilter")?.Attribute("type") ?? string.Empty);
        AssertEx.Equal("0", (string?)filterColumns[4].Element(MainNs + "top10")?.Attribute("top") ?? string.Empty);

        var sortState = autoFilter.Element(MainNs + "sortState");
        AssertEx.Equal("A2:E6", ((string?)sortState?.Attribute("ref") ?? string.Empty).ToUpperInvariant());
        var sortConditions = sortState?.Elements(MainNs + "sortCondition").ToList() ?? new List<XElement>();
        AssertEx.Equal(3, sortConditions.Count);
        AssertEx.Equal("value", (string?)sortConditions[0].Attribute("sortBy") ?? string.Empty);
        AssertEx.Equal("High,Medium,Low", (string?)sortConditions[0].Attribute("customList") ?? string.Empty);
        AssertEx.Equal("cellColor", (string?)sortConditions[1].Attribute("sortBy") ?? string.Empty);
        AssertEx.Equal("4", (string?)sortConditions[1].Attribute("dxfId") ?? string.Empty);
        AssertEx.Equal("icon", (string?)sortConditions[2].Attribute("sortBy") ?? string.Empty);
        AssertEx.Equal("3TrafficLights1", (string?)sortConditions[2].Attribute("iconSet") ?? string.Empty);
        AssertEx.Equal("2", (string?)sortConditions[2].Attribute("iconId") ?? string.Empty);
    }

    private static void AdjacentColumnsAreCombinedAndReadConsistently()    {        using var temp = new TemporaryDirectory("worksheet-openxml-columns");        var path = temp.GetPath("columns.xlsx");        var workbook = new Workbook();        var sheet = workbook.Worksheets[0];        sheet.Name = "Columns";        sheet.Cells.Columns[0].Width = 15.5d;        sheet.Cells.Columns[1].Width = 15.5d;        sheet.Cells.Columns[3].IsHidden = true;        sheet.Cells["A1"].PutValue("A");        sheet.Cells["B1"].PutValue("B");        workbook.Save(path);        var loaded = new Workbook(path);        AssertEx.Equal(15.5d, loaded.Worksheets[0].Cells.Columns[0].Width ?? 0d);        AssertEx.Equal(15.5d, loaded.Worksheets[0].Cells.Columns[1].Width ?? 0d);        AssertEx.True(loaded.Worksheets[0].Cells.Columns[3].IsHidden);        var snapshot = ReadWorkbookSnapshot(path).Single();        AssertEx.Equal(2, snapshot.Columns.Count);        AssertColumn(snapshot, 0, 1, 15.5d, false);        AssertColumn(snapshot, 3, 3, null, true);        AssertEx.Equal("A", snapshot.Cells["A1"]);        AssertEx.Equal("B", snapshot.Cells["B1"]);    }    private static void MergeOnlyDimensionMatchesOpenXmlSdk()    {        using var temp = new TemporaryDirectory("worksheet-openxml-merge-only");        var path = temp.GetPath("merge-only.xlsx");        var workbook = new Workbook();        workbook.Worksheets[0].Name = "MergeOnly";        workbook.Worksheets[0].Cells.Merge(4, 5, 2, 2);        workbook.Save(path);        var loaded = new Workbook(path);        AssertEx.Equal(1, loaded.Worksheets[0].Cells.MergedCells.Count);        AssertEx.Equal(4, loaded.Worksheets[0].Cells.MergedCells[0].FirstRow);        AssertEx.Equal(5, loaded.Worksheets[0].Cells.MergedCells[0].FirstColumn);        var snapshot = ReadWorkbookSnapshot(path).Single();        AssertEx.Equal("F5:G6", snapshot.Dimension);        AssertEx.Equal(1, snapshot.MergeReferences.Count);        AssertEx.Equal("F5:G6", snapshot.MergeReferences[0]);    }    private static void OpenXmlCreatedVisibilityLoadsInLibrary()    {        using var temp = new TemporaryDirectory("worksheet-library-read-visibility");        var path = temp.GetPath("openxml-visibility.xlsx");        CreateOpenXmlWorkbook(path,            new OpenXmlSheetDefinition("Visible", null, MinimalWorksheetXml()),            new OpenXmlSheetDefinition("Hidden", "hidden", MinimalWorksheetXml()),            new OpenXmlSheetDefinition("VeryHidden", "veryHidden", MinimalWorksheetXml()));        var loaded = new Workbook(path);        AssertEx.Equal(VisibilityType.Visible, loaded.Worksheets["Visible"].VisibilityType);        AssertEx.Equal(VisibilityType.Hidden, loaded.Worksheets["Hidden"].VisibilityType);        AssertEx.Equal(VisibilityType.VeryHidden, loaded.Worksheets["VeryHidden"].VisibilityType);        var snapshot = ReadWorkbookSnapshot(path);        AssertEx.Equal(3, snapshot.Count);        AssertEx.Equal("Hidden", snapshot[1].Visibility);        AssertEx.Equal("VeryHidden", snapshot[2].Visibility);    }    private static void OpenXmlCreatedSettingsAndValuesLoadInLibrary()    {        using var temp = new TemporaryDirectory("worksheet-library-read-settings");        var path = temp.GetPath("openxml-settings.xlsx");        CreateOpenXmlWorkbook(path,            new OpenXmlSheetDefinition(                "Layout",                "hidden",                "<?xml version=\"1.0\" encoding=\"utf-8\"?><worksheet xmlns=\"http://schemas.openxmlformats.org/spreadsheetml/2006/main\"><sheetPr><tabColor rgb=\"FF224466\"/></sheetPr><dimension ref=\"A1:C4\"/><sheetViews><sheetView workbookViewId=\"0\" showGridLines=\"0\" showRowColHeaders=\"0\" showZeros=\"0\" rightToLeft=\"1\" zoomScale=\"85\"/></sheetViews><sheetProtection sheet=\"1\" objects=\"1\" scenarios=\"1\" formatCells=\"1\" insertRows=\"1\" autoFilter=\"1\" selectLockedCells=\"1\" selectUnlockedCells=\"1\"/><cols><col min=\"1\" max=\"1\" width=\"18.25\" customWidth=\"1\"/><col min=\"3\" max=\"3\" hidden=\"1\"/></cols><sheetData><row r=\"1\"><c r=\"A1\" t=\"inlineStr\"><is><t>Merged</t></is></c></row><row r=\"2\" ht=\"22.5\" customHeight=\"1\"/><row r=\"4\" hidden=\"1\"><c r=\"C4\"><v>99</v></c></row></sheetData><mergeCells count=\"1\"><mergeCell ref=\"A1:B2\"/></mergeCells></worksheet>"));        var loaded = new Workbook(path);        WorksheetScenarioFactory.AssertWorksheetSettings(loaded);        var snapshot = ReadWorkbookSnapshot(path).Single();        AssertEx.Equal("Merged", snapshot.Cells["A1"]);        AssertEx.Equal("99", snapshot.Cells["C4"]);    }    private static void OpenXmlCreatedSheetViewLoadsInLibrary()    {        using var temp = new TemporaryDirectory("worksheet-library-read-view");        var path = temp.GetPath("openxml-view.xlsx");        CreateOpenXmlWorkbook(path,            new OpenXmlSheetDefinition(                "ViewSheet",                null,                "<?xml version=\"1.0\" encoding=\"utf-8\"?><worksheet xmlns=\"http://schemas.openxmlformats.org/spreadsheetml/2006/main\"><sheetPr><tabColor rgb=\"FF0A141E\"/></sheetPr><sheetViews><sheetView workbookViewId=\"0\" showGridLines=\"0\" showRowColHeaders=\"0\" showZeros=\"0\" rightToLeft=\"1\" zoomScale=\"140\"/></sheetViews><sheetData/></worksheet>"));        var loaded = new Workbook(path);        var sheet = loaded.Worksheets[0];        AssertEx.Equal(Color.FromArgb(255, 10, 20, 30), sheet.TabColor);        AssertEx.False(sheet.ShowGridlines);        AssertEx.False(sheet.ShowRowColumnHeaders);        AssertEx.False(sheet.ShowZeros);        AssertEx.True(sheet.RightToLeft);        AssertEx.Equal(140, sheet.Zoom);    }    private static void OpenXmlCreatedSheetProtectionLoadsInLibrary()
    {
        using var temp = new TemporaryDirectory("worksheet-library-read-protection");
