    private static void AddAutoFilterStylesPart(string path)
    {
        using var document = SpreadsheetDocument.Open(path, true);
        var workbookPart = document.WorkbookPart ?? throw new InvalidOperationException("WorkbookPart is missing.");
        var stylesPart = workbookPart.AddNewPart<WorkbookStylesPart>();
        WriteXmlPart(stylesPart, "<?xml version=\"1.0\" encoding=\"utf-8\"?><styleSheet xmlns=\"http://schemas.openxmlformats.org/spreadsheetml/2006/main\"><fonts count=\"1\"><font><sz val=\"11\"/><name val=\"Calibri\"/></font></fonts><fills count=\"2\"><fill><patternFill patternType=\"none\"/></fill><fill><patternFill patternType=\"gray125\"/></fill></fills><borders count=\"1\"><border><left/><right/><top/><bottom/><diagonal/></border></borders><cellStyleXfs count=\"1\"><xf numFmtId=\"0\" fontId=\"0\" fillId=\"0\" borderId=\"0\"/></cellStyleXfs><cellXfs count=\"1\"><xf numFmtId=\"0\" fontId=\"0\" fillId=\"0\" borderId=\"0\" xfId=\"0\"/></cellXfs><cellStyles count=\"1\"><cellStyle name=\"Normal\" xfId=\"0\" builtinId=\"0\"/></cellStyles><dxfs count=\"5\"><dxf/><dxf/><dxf/><dxf/><dxf/></dxfs></styleSheet>");
    }

    private static void OpenXmlCreatedColumnsLoadInLibrary()    {        using var temp = new TemporaryDirectory("worksheet-library-read-columns");        var path = temp.GetPath("openxml-columns.xlsx");        CreateOpenXmlWorkbook(path,            new OpenXmlSheetDefinition(                "Columns",                null,                "<?xml version=\"1.0\" encoding=\"utf-8\"?><worksheet xmlns=\"http://schemas.openxmlformats.org/spreadsheetml/2006/main\"><dimension ref=\"A1:B1\"/><cols><col min=\"1\" max=\"2\" width=\"15.5\" customWidth=\"1\"/><col min=\"4\" max=\"4\" hidden=\"1\"/></cols><sheetData><row r=\"1\"><c r=\"A1\" t=\"inlineStr\"><is><t>A</t></is></c><c r=\"B1\" t=\"inlineStr\"><is><t>B</t></is></c></row></sheetData></worksheet>"));        var loaded = new Workbook(path);        AssertEx.Equal(15.5d, loaded.Worksheets[0].Cells.Columns[0].Width ?? 0d);        AssertEx.Equal(15.5d, loaded.Worksheets[0].Cells.Columns[1].Width ?? 0d);        AssertEx.True(loaded.Worksheets[0].Cells.Columns[3].IsHidden);        AssertEx.Equal("A", loaded.Worksheets[0].Cells["A1"].StringValue);        AssertEx.Equal("B", loaded.Worksheets[0].Cells["B1"].StringValue);    }    private static void OpenXmlCreatedMergeOnlyDimensionLoadsInLibrary()    {        using var temp = new TemporaryDirectory("worksheet-library-read-merge-only");        var path = temp.GetPath("openxml-merge-only.xlsx");        CreateOpenXmlWorkbook(path,            new OpenXmlSheetDefinition(                "MergeOnly",                null,                "<?xml version=\"1.0\" encoding=\"utf-8\"?><worksheet xmlns=\"http://schemas.openxmlformats.org/spreadsheetml/2006/main\"><dimension ref=\"F5:G6\"/><sheetData/><mergeCells count=\"1\"><mergeCell ref=\"F5:G6\"/></mergeCells></worksheet>"));        var loaded = new Workbook(path);        AssertEx.Equal(1, loaded.Worksheets[0].Cells.MergedCells.Count);        AssertEx.Equal(4, loaded.Worksheets[0].Cells.MergedCells[0].FirstRow);        AssertEx.Equal(5, loaded.Worksheets[0].Cells.MergedCells[0].FirstColumn);        var snapshot = ReadWorkbookSnapshot(path).Single();        AssertEx.Equal("F5:G6", snapshot.Dimension);        AssertEx.Equal("F5:G6", snapshot.MergeReferences.Single());    }    private static void AssertRow(WorksheetSnapshot snapshot, int rowIndex, double? height, bool hidden)    {        AssertEx.True(snapshot.Rows.TryGetValue(rowIndex, out var row), $"Expected row {rowIndex} to exist in Open XML snapshot.");        AssertEx.Equal(height, row!.Height);        AssertEx.Equal(hidden, row.Hidden);    }    private static void AssertColumn(WorksheetSnapshot snapshot, int minColumnIndex, int maxColumnIndex, double? width, bool hidden)    {        var column = snapshot.Columns.SingleOrDefault(delegate(ColumnSnapshot item) { return item.MinColumnIndex == minColumnIndex && item.MaxColumnIndex == maxColumnIndex; });        AssertEx.NotNull(column, $"Expected column range {minColumnIndex}:{maxColumnIndex} to exist in Open XML snapshot.");        AssertEx.Equal(width, column!.Width);        AssertEx.Equal(hidden, column.Hidden);    }    private static List<WorksheetSnapshot> ReadWorkbookSnapshot(string workbookPath)    {        using var document = SpreadsheetDocument.Open(workbookPath, false);        var workbookPart = document.WorkbookPart ?? throw new InvalidOperationException("WorkbookPart is missing.");        var sharedStrings = LoadSharedStrings(workbookPart);        var workbookXml = XDocument.Load(workbookPart.GetStream());        var snapshots = new List<WorksheetSnapshot>();        foreach (var sheet in workbookXml.Root?.Element(MainNs + "sheets")?.Elements(MainNs + "sheet") ?? Enumerable.Empty<XElement>())        {            var relationshipId = (string?)sheet.Attribute(RelationshipNs + "id");            if (string.IsNullOrWhiteSpace(relationshipId))            {                continue;            }            if (workbookPart.GetPartById(relationshipId) is not WorksheetPart worksheetPart)            {                continue;            }            snapshots.Add(ReadWorksheetSnapshot(sheet, worksheetPart, sharedStrings));        }        return snapshots;    }    private static WorksheetSnapshot ReadWorksheetSnapshot(XElement sheetElement, WorksheetPart worksheetPart, IReadOnlyList<string> sharedStrings)    {        var worksheetXml = XDocument.Load(worksheetPart.GetStream());        var worksheetRoot = worksheetXml.Root ?? throw new InvalidOperationException("Worksheet XML is empty.");        var sheetName = (string?)sheetElement.Attribute("name") ?? string.Empty;        string visibility;        switch ((string?)sheetElement.Attribute("state"))        {            case "hidden":                visibility = "Hidden";                break;            case "veryHidden":                visibility = "VeryHidden";                break;            default:                visibility = "Visible";                break;        }        var rows = new Dictionary<int, RowSnapshot>();        foreach (var row in worksheetRoot.Element(MainNs + "sheetData")?.Elements(MainNs + "row") ?? Enumerable.Empty<XElement>())        {            if (!int.TryParse((string?)row.Attribute("r"), NumberStyles.Integer, CultureInfo.InvariantCulture, out var rowIndex))            {                continue;            }            rows[rowIndex - 1] = new RowSnapshot(                TryParseDouble((string?)row.Attribute("ht")),                ParseBool((string?)row.Attribute("hidden")));        }        var columns = new List<ColumnSnapshot>();        foreach (var column in worksheetRoot.Element(MainNs + "cols")?.Elements(MainNs + "col") ?? Enumerable.Empty<XElement>())        {            if (!int.TryParse((string?)column.Attribute("min"), NumberStyles.Integer, CultureInfo.InvariantCulture, out var minColumnIndex)                || !int.TryParse((string?)column.Attribute("max"), NumberStyles.Integer, CultureInfo.InvariantCulture, out var maxColumnIndex))            {                continue;            }            columns.Add(new ColumnSnapshot(                minColumnIndex - 1,                maxColumnIndex - 1,                TryParseDouble((string?)column.Attribute("width")),                ParseBool((string?)column.Attribute("hidden"))));        }        var merges = new List<string>();        foreach (var mergeCell in worksheetRoot.Element(MainNs + "mergeCells")?.Elements(MainNs + "mergeCell") ?? Enumerable.Empty<XElement>())        {            merges.Add(((string?)mergeCell.Attribute("ref") ?? string.Empty).ToUpperInvariant());        }        var cells = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);        foreach (var cell in worksheetRoot.Descendants(MainNs + "c"))        {            var cellReference = ((string?)cell.Attribute("r") ?? string.Empty).ToUpperInvariant();            if (string.IsNullOrWhiteSpace(cellReference))            {                continue;            }            cells[cellReference] = ReadCellValue(cell, sharedStrings);        }        var sheetView = worksheetRoot.Element(MainNs + "sheetViews")?.Element(MainNs + "sheetView");        var sheetProtection = worksheetRoot.Element(MainNs + "sheetProtection");        return new WorksheetSnapshot(            sheetName,            visibility,            (string?)worksheetRoot.Element(MainNs + "dimension")?.Attribute("ref") ?? string.Empty,            ((string?)worksheetRoot.Element(MainNs + "sheetPr")?.Element(MainNs + "tabColor")?.Attribute("rgb") ?? string.Empty).ToUpperInvariant(),            ParseViewBool((string?)sheetView?.Attribute("showGridLines"), true),            ParseViewBool((string?)sheetView?.Attribute("showRowColHeaders"), true),            ParseViewBool((string?)sheetView?.Attribute("showZeros"), true),            ParseViewBool((string?)sheetView?.Attribute("rightToLeft"), false),            TryParseInt((string?)sheetView?.Attribute("zoomScale")) ?? 100,            ParseProtectionBool((string?)sheetProtection?.Attribute("sheet"), sheetProtec